const input = $input.first().json?.data;
const datasets = Array.isArray(input?.results) ? input.results : [];

const URL_REGEX = /https?:\/\/[^\s)"'<>]+/gi;

function extractUrlsFromText(value) {
  if (typeof value !== 'string' || !value.trim()) return [];
  return value.match(URL_REGEX) ?? [];
}

function pushLink(collector, dataset, source, field, url) {
  if (!url || typeof url !== 'string') return;
  const cleaned = url.trim();
  if (!cleaned) return;

  collector.push({
    dataset_id: dataset.id ?? null,
    dataset_name: dataset.name ?? '(unknown)',
    dataset_title: dataset.title ?? dataset.name ?? '(unknown)',
    source,
    field,
    url: cleaned,
  });
}

const links = [];

for (const d of datasets) {
  // Direct dataset-level URL fields
  pushLink(links, d, 'dataset', 'url', d.url);
  pushLink(links, d, 'dataset', 'author_email', d.author_email && d.author_email.includes('@') ? `mailto:${d.author_email}` : null);
  pushLink(links, d, 'dataset', 'maintainer_email', d.maintainer_email && d.maintainer_email.includes('@') ? `mailto:${d.maintainer_email}` : null);

  // URLs embedded in textual metadata
  for (const field of ['notes', 'title', 'author', 'maintainer']) {
    for (const found of extractUrlsFromText(d[field])) {
      pushLink(links, d, 'dataset', field, found);
    }
  }

  // CKAN extras can contain urls or text with urls
  if (Array.isArray(d.extras)) {
    for (const ex of d.extras) {
      const key = ex?.key ?? 'extras';
      const val = ex?.value;
      if (typeof val === 'string') {
        if (/^https?:\/\//i.test(val.trim())) {
          pushLink(links, d, 'dataset', `extras.${key}`, val);
        }
        for (const found of extractUrlsFromText(val)) {
          pushLink(links, d, 'dataset', `extras.${key}`, found);
        }
      }
    }
  }

  // Resource URLs and descriptions
  const resources = Array.isArray(d.resources) ? d.resources : [];
  for (const r of resources) {
    pushLink(links, d, 'resource', `resource.url:${r?.name ?? r?.id ?? 'unknown'}`, r?.url);
    for (const found of extractUrlsFromText(r?.description)) {
      pushLink(links, d, 'resource', `resource.description:${r?.name ?? r?.id ?? 'unknown'}`, found);
    }
  }
}

// Deduplicate by dataset + url + field + source
const seen = new Set();
const deduped = [];
for (const l of links) {
  const key = `${l.dataset_id}|${l.source}|${l.field}|${l.url}`;
  if (seen.has(key)) continue;
  seen.add(key);
  deduped.push(l);
}

if (deduped.length === 0) {
  return [{ json: { _noLinks: true, message: 'No links found in scanned datasets.' } }];
}

return deduped.map((l) => ({ json: l }));

const input = $input.first().json;

const status = Number(input.statusCode ?? input.code ?? 0) || 0;
const ok = status >= 200 && status < 300;
const redirect = status >= 300 && status < 400;

const out = {
  dataset_id: input.dataset_id,
  dataset_name: input.dataset_name,
  dataset_title: input.dataset_title,
  source: input.source,
  field: input.field,
  url: input.url,
  method: 'HEAD',
  statusCode: status || null,
  ok,
  redirect,
  needsFallbackGet: !ok && !redirect,
  error: input.error?.message ?? input.message ?? null,
};

return [{ json: out }];

const input = $input.first().json;
const status = Number(input.statusCode ?? input.code ?? 0) || 0;

let state = 'broken';
if (status >= 200 && status < 300) state = 'ok';
else if (status >= 300 && status < 400) state = 'redirect';
else if (!status && input.error) state = 'error';

return [{
  json: {
    dataset_id: input.dataset_id,
    dataset_name: input.dataset_name,
    dataset_title: input.dataset_title,
    source: input.source,
    field: input.field,
    url: input.url,
    method: 'GET',
    statusCode: status || null,
    state,
    error: input.error?.message ?? input.message ?? null,
  }
}];

const i = $input.first().json;
let state = 'broken';
if (i.ok) state = 'ok';
else if (i.redirect) state = 'redirect';
else if (!i.statusCode && i.error) state = 'error';

return [{
  json: {
    dataset_id: i.dataset_id,
    dataset_name: i.dataset_name,
    dataset_title: i.dataset_title,
    source: i.source,
    field: i.field,
    url: i.url,
    method: 'HEAD',
    statusCode: i.statusCode,
    state,
    error: i.error ?? null,
  }
}];

const items = $input.all().map(i => i.json);

if (items.length === 0) {
  return [{ json: { message: 'No links validated.', totalLinks: 0, brokenLinks: 0, byDataset: [] } }];
}

const brokenStates = new Set(['broken', 'error']);
const redirectStates = new Set(['redirect']);

const byDatasetMap = new Map();
for (const r of items) {
  const key = r.dataset_id ?? r.dataset_name ?? 'unknown';
  if (!byDatasetMap.has(key)) {
    byDatasetMap.set(key, {
      dataset_id: r.dataset_id,
      dataset_name: r.dataset_name,
      dataset_title: r.dataset_title,
      totalLinks: 0,
      ok: 0,
      redirects: 0,
      broken: 0,
      links: [],
    });
  }

  const ds = byDatasetMap.get(key);
  ds.totalLinks += 1;
  if (r.state === 'ok') ds.ok += 1;
  else if (redirectStates.has(r.state)) ds.redirects += 1;
  else if (brokenStates.has(r.state)) ds.broken += 1;

  ds.links.push({
    source: r.source,
    field: r.field,
    url: r.url,
    method: r.method,
    statusCode: r.statusCode,
    state: r.state,
    error: r.error ?? null,
  });
}

const byDataset = Array.from(byDatasetMap.values())
  .sort((a, b) => b.broken - a.broken || a.dataset_name.localeCompare(b.dataset_name));

const totalLinks = items.length;
const brokenLinks = items.filter((r) => brokenStates.has(r.state)).length;
const redirectLinks = items.filter((r) => redirectStates.has(r.state)).length;
const okLinks = items.filter((r) => r.state === 'ok').length;

return [{
  json: {
    generatedAt: new Date().toISOString(),
    totalDatasetsWithLinks: byDataset.length,
    totalLinks,
    okLinks,
    redirectLinks,
    brokenLinks,
    byDataset,
  }
}];

return [{
  json: {
    generatedAt: new Date().toISOString(),
    totalDatasetsWithLinks: 0,
    totalLinks: 0,
    okLinks: 0,
    redirectLinks: 0,
    brokenLinks: 0,
    byDataset: [],
    message: 'No links found in dataset metadata/resources.'
  }
}];
